     Int // Prix de la cotisation\n  year        Int // Année de la cotisation\n  isActive    Boolean @default(true) // Si la cotisation est actif\n  personId    String\n  paymentId   String  @unique // ID du paiement\n\n  // Relations\n  person  Person? @relation(fields: [personId], references: [id])\n  payment Payment @relation(fields: [paymentId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"member_ships\")\n}\n\nmodel Donation {\n  id        String  @id @default(cuid())\n  title     String // Titre de la section\n  message   String? // Message de la donation\n  amount    Int // Prix de la donation\n  personId  String\n  paymentId String  @unique // ID du paiement\n\n  // Relations\n  person  Person? @relation(fields: [personId], references: [id])\n  payment Payment @relation(fields: [paymentId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"donations\")\n}\n\nmodel Address {\n  id          String @id @default(cuid())\n  address     String // Adresse de la personne\n  city        String // Ville de la personne\n  country     String // Pays de la personne\n  zipCode     String // Code postal de la personne\n  state       String // État de la personne\n  countryCode String // Code pays de la personne\n\n  person Person[] // Personnes liées à l'adresse\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"addresses\")\n}\n\nmodel Contact {\n  id      String @id @default(cuid())\n  phone   String // Numéro de téléphone de l'association\n  email   String // Email de l'association\n  address String @default(\"\") // Rue et numéro\n  city    String @default(\"\") // Ville\n  zipCode String @default(\"\") // Code postal\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"contacts\")\n}\n\nenum PopupType {\n  IMAGE_TEXT\n  PROSPECTUS\n}\n\nmodel Popup {\n  id       String    @id @default(cuid())\n  type     PopupType @default(IMAGE_TEXT)\n  isActive Boolean   @default(false)\n\n  // IMAGE_TEXT\n  badge       String?\n  title       String?\n  subtitle    String?\n  description String?\n  date        String?\n  location    String?\n  imageId     String? // Cloudinary publicId\n  ctaLabel    String?\n  ctaUrl      String?\n\n  // PROSPECTUS\n  prospectusIds String[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"popups\")\n}\n\nmodel Banner {\n  id        String   @id @default(cuid())\n  isActive  Boolean  @default(false)\n  badge     String?\n  title     String\n  date      String?\n  location  String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"banners\")\n}\n\nenum ContactSubmissionStatus {\n  PENDING\n  READ\n  REPLIED\n}\n\nmodel ContactSubmission {\n  id        String                  @id @default(cuid())\n  firstName String\n  lastName  String\n  email     String\n  phone     String?\n  subject   String\n  message   String\n  status    ContactSubmissionStatus @default(PENDING)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"contact_submissions\")\n}\n\n/// Type de demande configurable (libellé, ordre, précision optionnelle obligatoire).\nmodel BeneficiaryDemandType {\n  id             String   @id @default(cuid())\n  label          String\n  sortOrder      Int      @default(0)\n  isActive       Boolean  @default(true)\n  /// Si vrai, le formulaire de suivi exige un champ « précision » (ex. « Autre »).\n  requiresDetail Boolean  @default(false)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  beneficiaries Beneficiary[]\n\n  @@map(\"beneficiary_demand_types\")\n}\n\n/// Type de document fourni configurable (code stable dans le JSON de la fiche).\nmodel BeneficiaryDocumentType {\n  id                  String   @id @default(cuid())\n  /// Clé stockée dans `beneficiaries.documentsProvided` (tableau JSON).\n  code                String   @unique\n  label               String\n  sortOrder           Int      @default(0)\n  isActive            Boolean  @default(true)\n  /// Si coché : précision texte obligatoire pour ce document (ex. « Autre »).\n  requiresOtherDetail Boolean  @default(false)\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n\n  @@map(\"beneficiary_document_types\")\n}\n\n/// Fiche Demande bénéficiaire / permanence administrative (ex-Google Form suivi).\nmodel Beneficiary {\n  id                      String                  @id @default(cuid())\n  permanenceDate          DateTime                @db.Date\n  /// Un ou plusieurs types de demande (sélection multiple au formulaire).\n  demandTypes             BeneficiaryDemandType[]\n  /// Texte libre si au moins un type exige une précision (`requiresDetail`).\n  requestDetail           String?\n  firstName               String\n  lastName                String\n  phone                   String?\n  email                   String?\n  notes                   String?\n  /// Données sensibles (mots de passe) : accès base restreint, pas d’exposition côté public.\n  birthDate               DateTime?               @db.Date\n  birthCountry            String?\n  birthMunicipality       String?\n  fatherName              String?\n  motherName              String?\n  gmailAccount            String?\n  gmailPassword           String?\n  ekadiLogin              String?\n  ekadiPassword           String?\n  /// Tableau JSON de codes `BeneficiaryDocumentType.code`.\n  documentsProvided       Json?\n  /// Précision si « Autre » document est coché.\n  documentOtherDetail     String?\n  requestStatus           String?\n  statusComment           String?\n  assignedResponsibleName String?\n  paymentResponsible      String?\n  paymentOtherDetail      String?\n  submittedByPersonId     String?\n\n  person Person? @relation(fields: [submittedByPersonId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([permanenceDate])\n  @@index([submittedByPersonId])\n  @@map(\"beneficiaries\")\n}\n\n/// Liste de présence à la permanence administrative (remplace l’ancien Google Form).\nmodel PermanenceAdminPresenceVolunteer {\n  id                  String   @id @default(cuid())\n  permanenceDate      DateTime @db.Date\n  memberFullName      String\n  hours               Decimal  @db.Decimal(5, 2)\n  comment             String?\n  submittedByPersonId String?\n\n  person Person? @relation(fields: [submittedByPersonId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([permanenceDate])\n  @@index([submittedByPersonId])\n  @@map(\"permanence_admin_presence_volunteers\")\n}\n\n/// Créneaux affichés sur le pôle « Démarche administrative » (synchronisés site + dashboard).\nmodel AdministrativePermanenceSlot {\n  id        String   @id @default(cuid())\n  slotDate  DateTime @unique @db.Date\n  /// Heure locale au format 24h « HH:mm » (ex. 14:00).\n  startTime String\n  endTime   String\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([slotDate])\n  @@map(\"administrative_permanence_slots\")\n}\n\n/// Texte libre pour la carte « Horaires » (pôle administratif). Une seule ligne `default`.\nmodel AdministrativePermanenceSettings {\n  id               String   @id @default(\"default\")\n  /// Si renseigné, remplace le texte généré automatiquement dans la carte Horaires.\n  horairesCardText String?  @db.Text\n  updatedAt        DateTime @updatedAt\n\n  @@map(\"administrative_permanence_settings\")\n}\n\nmodel Order {\n  id          String @id @default(cuid())\n  orderNumber String // Numéro de la commande\n  totalAmount Int // Montant total de la commande\n  paymentId   String @unique // ID du paiement\n  personId    String\n\n  // Relations\n  person  Person      @relation(fields: [personId], references: [id])\n  items   OrderItem[] // Items de la commande\n  payment Payment     @relation(fields: [paymentId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"orders\")\n}\n\n// Table de jointure pour Order et Product avec quantité\nmodel OrderItem {\n  id        String @id @default(cuid())\n  orderId   String // ID de la commande\n  productId String // ID du produit\n  quantity  Int // Quantité commandée\n  price     Int // Prix unitaire au moment de la commande (en centimes)\n  subtotal  Int // Sous-total (quantity * price) en centimes\n\n  // Relations\n  order   Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([orderId])\n  @@index([productId])\n  @@map(\"order_items\")\n}\n\nmodel Payment {\n  id               String        @id @default(cuid())\n  paymentReference String        @unique // Référence de paiement Stripe\n  amount           Int // Montant du paiement\n  status           PaymentStatus // Statut du paiement\n  type             String // Type de paiement\n  paymentMethod    String // Méthode de paiement\n  paymentDate      DateTime      @default(now()) // Date de paiement\n  personId         String\n\n  // Relations\n  person      Person       @relation(fields: [personId], references: [id], onDelete: Cascade)\n  orders      Order[] // Commandes liées au paiement\n  donations   Donation[] // Donations liées au paiement\n  memberShips MemberShip[] // Adhésions liées au paiement\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"payments\")\n}\n\nmodel PaymentHistory {\n  id          String        @id @default(cuid())\n  paymentId   String // ID du paiement\n  personId    String // ID de la personne \n  status      PaymentStatus // Statut du paiement\n  type        String // Type de paiement\n  paymentDate DateTime      @default(now()) // Date de paiement\n\n  // Relations\n  person Person? @relation(fields: [personId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"payment_histories\")\n}\n\n// ── Better Auth ────────────────────────────────────────────────────────────────\n\nmodel User {\n  id            String    @id\n  name          String\n  email         String    @unique\n  emailVerified Boolean\n  image         String?\n  role          String?\n  banned        Boolean?\n  banReason     String?\n  banExpires    DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  sessions Session[]\n  accounts Account[]\n\n  @@map(\"user\")\n}\n\nmodel Session {\n  id        String   @id\n  expiresAt DateTime\n  token     String   @unique\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  ipAddress String?\n  userAgent String?\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"session\")\n}\n\nmodel Account {\n  id                    String    @id\n  accountId             String\n  providerId            String\n  userId                String\n  user                  User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  accessToken           String?\n  refreshToken          String?\n  idToken               String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String?\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  @@map(\"account\")\n}\n\nmodel Verification {\n  id         String   @id\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@map(\"verification\")\n}\n\n/// Dépôt étudiant — démarche Campus France (formulaire public pôle administratif).\nmodel CampuceFranceStudentSubmission {\n  id                    String    @id @default(cuid())\n  firstName             String\n  lastName              String\n  phone                 String\n  email                 String\n  /// Année de dépôt (clé de déduplication métier).\n  submissionYear        Int\n  country               String\n  acceptanceCity        String\n  universitySite        String\n  academicLevel         String\n  program               String\n  /// Types d'aide sollicités (plusieurs possibles sur le même dossier).\n  helpTypes             String[]\n  visaAppointmentDate   DateTime? @db.Date\n  comment               String?   @db.Text\n  /// Identifiants Cloudinary (`gam/campuce-france`), jusqu’à 3 fichiers (PDF ou image).\n  filesIds              String[]\n  /// Suivi admin : dossier complet (validation interne).\n  isComplete            Boolean   @default(false)\n  /// Suivi admin : attestation d'hébergement fournie.\n  hasHostingAttestation Boolean   @default(false)\n  /// Suivi admin : logement trouvé (si aide sollicitée = logement).\n  hasHousingFound       Boolean   @default(false)\n  /// Suivi admin : visa obtenu.\n  hasVisa               Boolean   @default(false)\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  @@unique([submissionYear, phone, email])\n  @@index([createdAt])\n  @@index([submissionYear])\n  @@map(\"campuce_france_student_submissions\")\n}\n",
